(678, 'LAPTOP', 'Acer Laptop AL15-51M-55R1', 'Acer Laptop AL15-51M-55R1', '', 'Processor: at least intel core i5 (up to 4.50 Ghz) or its equivalent        \nGraphics Display: at least 15.6 FHD IPS        \nMemory: at least 8GB Memory        \nStorage: at least 256 GB SSD + 1 TB HDD or at least 1 TB SSD        \nOS: at least Windows 11 Genuine and pre-loaded        \nMicrosoft Office installed        \nConnectivity: with at least built-in WLAN, ethernet port, Bluetooth, HDMI, USB', '2025-01-07', 'N/A', '', 'NEW', '2', 'CHARLEMAGNE T. VILLACORTE'),
(679, 'DESKTOP', 'ACER ALL-IN-ONE DESKTOP ACER ASPIRE C24-1851 WITCH WACOM CTL-472', 'All in one Desktop with Digital Pen', 'OPD', 'Processor: at least intel core i5 or its equivalent or higher        \nMemory: at least 8 gb        \nStorage: at least 256 GB SSD + 1 TB HDD        \nOS: at least Windows 11 GEnuine and pre-loaded        \nWebcam: at least 1080p        \nConnectivity: with at least built-in WLAN, ethernet port, Bluetooth, HDMI, USB        \nDisplay: at least 23.8 inch FHD        \nWith digital pen, tablet size: at least 210x146x8.7 mm        \nBattery free pen        \nUSB wired keyboard and wired mouse with uninterruptible power supply', '2025-01-07', 'N/A', '', 'NEW', '10', 'CHARLEMAGNE T. VILLACORTE'),
(680, 'PRINTER', 'HP DESIGN JET T850 PLOTTER', 'HP DESIGN JET T850 PLOTTER', 'EFMS', 'Print line drawings: at least 25 sec/page on A1/D, 82 A1/D prints per hour        \nPrint resolution: at most 2400 x 1200 optimized PI        \nInk types: at least Dye-based (C, M, Y); pigment-based (mK)        \nMinimum line width: at least 0.02mm (0.0008 in)        \nMedia Handling: at least with sheet feed, roll feed, inout tray, media bin, automatic cutter        \n\"Size: Rolls: at least 279 to 914 mm        \nSheets: at least 210 x 279 to 914 x 1897 mm        \nStandard sheets: at least A4, A3, A2, A1, A0        \nScan/copy resolution: at least 600 dpi        \nMaximum scan: at least 914mm x 2.77mm        \nCopt reduction/enlargement: at least 50 to 400%        \nApplications: at least Line drawings, rendering, presentations        \nMemory:at least 1 GB        \nConnectivity: at least Ethernet, wifi, wifi-direct        \nOS: compatible with windows and mac        \nWith warranty of at least 2 years for head cleaning and other preventive and corrective maintenance        \nOther inclusions: printhead, ink cartridges, printer stand, spindle, quick reference sample, setup poster,        \nstart up software, power cord, refeed preventers        \nWith consumables: Printer ink (BCYM-5 sets), 10 rolls white paper (80/85 gsm; 30\" x 50\" yards), 10 rolls        \ntracing paper (80/85 gsm; 30\" x 50\" yards.        \nTesting, Commissioning and Orientation', '2025-01-28', 'N/A', '', 'NEW', '1', 'CHARLEMAGNE T. VILLACORTE'),
(681, 'LAPTOP', 'ACER PREDATOR ORION POS-650', 'ACER PREDATOR ORION POS-650 W/ MSI MONITOR', 'DENTAL', 'CPU: at least i7 10th gen or its equivalent or higher        \nMotherboard: at least z690 or its equivalent or higher        \nPorts: at least PcIe 5.0 DDR5, LAN, Bluetooth, thunderbolt 4.4xM.2        \nFront Panel USB 3.2 Gen 2x2 Type-C connector        \nGraphics card: at least RTX 3060 XC        \nGaming, 12gb GDDR6 Dual fan        \nRAM: at least 64GB DDR5 4000MHZ or higher        \nStorage: at least 1TB PcIe Gen3xX4 NVMe M.2-2280 SSD and at least 2TB SATA 36gb/s, 3.5\"        \nInternal HardDrive        \nMust be Compatible with Cone Beam Computed Tomography Machine (CBCT)        \nHyperion X9 PRO SN 70A 10263', '2025-02-27', 'N/A', '', 'NEW', '1', 'CHARLEMAGNE T. VILLACORTE'),
(682, 'NETWORK SWITCH', 'TP LINK TL SG3428MP', 'GIGABIT POE NETWORK SWITCH 24 PORTS', 'IHOMP', 'Manageable Network switch 24-port gigabit        \nAt least 24 x 10/100/1000/Mbps RJ45 ports        \nAt least 48 Gps switching capacity        \nRack mountable        \nPOE enabled        \nSupports L2+/L3 features', '2025-03-21', '5  YEARS', '', 'NEW', '16', 'CHARLEMAGNE T. VILLACORTE'),
(683, 'ROUTER', 'TP LINK AX23/1800', 'WIFI 6 ROUTER', 'IHOMP', 'at least 5 GHz, 1201 Mbps (802.11 ax)        \nand 2.4Ghz: 574 Mbps  (802.11 ax)        \nsupport at least 1 x Gigabit WAN Port and 4x Gigabit        \nLAN ports        \nWIFI encryption: WPA, WPA2, WPA3        \nWPA/WPA2 - Enterprise (802.1x)', '2025-03-17', '5  YEARS', '', 'NEW', '4', 'CHARLEMAGNE T. VILLACORTE'),
(684, 'CABLE', 'LOCAL AREA NETWORK CABLE (Cat6) OUTDOOR', 'UTP CABLE', 'IHOMP', 'UTP CAT6 CCA        \nHigh quality technology        \nBlack in color        \nat least 300 meters', '2025-03-21', 'CONSUMABLES', '', 'NEW', '30', 'CHARLEMAGNE T. VILLACORTE'),
